async function main() {
  console.log("🌱 Seed počinje...\n");

  // Admin
  const email = process.env.ADMIN_EMAIL ?? "admin@itsecurity.rs";
  const pass  = process.env.ADMIN_PASSWORD ?? "promeni-me-odmah";
  await prisma.user.upsert({
    where: { email },
    update: {},
    create: { email, name: "Admin", password: await bcrypt.hash(pass, 10), role: "ADMIN" },
  });
  console.log("✅ Admin:", email);

  // Kategorije
  const catIds: Record<string, string> = {};
  for (const cat of CATEGORIES.filter(c => !c.parent)) {
    const r = await prisma.category.upsert({
      where: { slug: cat.slug }, update: { name: cat.name },
      create: { name: cat.name, slug: cat.slug },
    });
    catIds[cat.slug] = r.id;
  }
  for (const cat of CATEGORIES.filter(c => c.parent)) {
    const r = await prisma.category.upsert({
      where: { slug: cat.slug },
      update: { name: cat.name, parentId: catIds[cat.parent!] },
      create: { name: cat.name, slug: cat.slug, parentId: catIds[cat.parent!] },
    });
    catIds[cat.slug] = r.id;
  }
  console.log(`✅ Kategorije: ${CATEGORIES.length}`);

  // Promo baneri
  await prisma.promoBanner.deleteMany();
  await prisma.promoBanner.createMany({ data: [
    { title: "HD Kamere — akcija", subtitle: "Hikvision, Dahua, TVT — do 30% popusta", badge: "-30%", href: "/shop?category=hd-kamere", bgColor: "#1d3eb8", txtColor: "#ffffff", order: 1 },
    { title: "Kompleti video nadzora", subtitle: "400€ — 4 kamere + snimač 4K + HDD", badge: "400€", href: "/shop?category=kompleti-video-nadzora", bgColor: "#0b1020", txtColor: "#f6d000", order: 2 },
    { title: "Alarmi i interfoni", subtitle: "Bežični alarmi i video interfoni na akciji", badge: "Akcija", href: "/shop?category=alarmi", bgColor: "#f6d000", txtColor: "#0b1020", order: 3 },
  ]});
  console.log("✅ Promo baneri");

  // Proizvodi
  let imported = 0, skipped = 0;
  for (const p of PRODUCTS) {
    const catId = p.categorySlug ? catIds[p.categorySlug] : undefined;
    const data = {
      wooId: p.wooId, name: p.name, slug: p.slug,
      description: p.description, brand: p.brand,
      price: p.price, regularPrice: p.regularPrice, salePrice: p.salePrice,
      showPrice: p.showPrice, inStock: p.inStock,
      images: p.images, attributes: p.attributes,
      active: true, categoryId: catId,
    };
    await prisma.product.upsert({
      where: { wooId: p.wooId },
      update: data,
      create: data,
    });
    imported++;
    if (imported % 50 === 0) console.log(`  → ${imported} proizvoda...`);
  }
  console.log(`\n✅ Proizvodi: ${imported} uvezeno, ${skipped} preskočeno`);
  console.log("\n🎉 Gotovo!");
}

main()
  .catch(e => { console.error(e); process.exit(1); })
  .finally(() => prisma.$disconnect());
